import org.hyperledger.fabric.sdk.Chaincode;
import org.hyperledger.fabric.sdk.ChaincodeStub;
import org.hyperledger.fabric.sdk.ProposalResponse;
import org.hyperledger.fabric.sdk.TransactionProposalRequest;

public class FabricExample {
 public static void main(String[] args) {
 // Create a Fabric network
 FabricNetwork network = new FabricNetwork();
 // Create a Chaincode
 Chaincode chaincode = new Chaincode();
 // Execute the Chaincode
 ProposalResponse response = network.executeChaincode(chaincode);
 // Print the result
 System.out.println(response.getChaincodeActionResponse().getResponse().toString());
 }
}
